using UnityEngine;using UnityEngine.AddressableAssets;using UnityEngine.SceneManagement;using System.Collections;namespace Kapuro2025Winter.Scripts.Stiring.Director{    public class PGDirector : MonoBehaviour    {    private Phase currentPhase = Phase.Start;    [SerializeField] private TimeController timeController;    [SerializeField] private UIController uiController;    [SerializeField] private EndEffectController endEffectController;    public event System.Action<Phase> OnChangePhase;        // Start is called once before the first execution of Update after the MonoBehaviour is created    void Start()    {        ChangePhase(Phase.Start);    }    void OnEnable()    {        uiController.OnFinishedSequence += () => ChangePhase(Phase.Right);        timeController.OnPhaseTimeReached += ChangePhase;        endEffectController.OnFinishEffect += ExitEndPart;    }    void OnDisable()    {        timeController.OnPhaseTimeReached -= ChangePhase;        endEffectController.OnFinishEffect -= ExitEndPart;    }        public void ChangePhase(Phase phase)    {        ExitPhase(currentPhase);        currentPhase = phase;        EnterPhase(currentPhase);        OnChangePhase?.Invoke(phase);    }    private void EnterPhase(Phase phase)    {        switch (phase)        {            case Phase.Start: EnterStartPart(); break;            case Phase.Right: EnterRightPart(); break;            case Phase.Left: EnterLeftPart(); break;            case Phase.Both: EnterBothPart(); break;            case Phase.End: EnterEndPart(); break;        }    }    private void EnterStartPart()    {        Debug.Log("Enter Start");    }    private void EnterRightPart()    {        Debug.Log("Enter Right");        timeController.StartTimer();    }    private void EnterLeftPart()    {        Debug.Log("Enter Left");    }    private void EnterBothPart()    {        Debug.Log("Enter Both");    }    private void EnterEndPart()    {        Debug.Log("Enter End");    }        private void ExitPhase(Phase phase)    {        switch (phase)        {            case Phase.Start: ExitStartPart(); break;            case Phase.Right: ExitRightPart(); break;            case Phase.Left: ExitLeftPart(); break;            case Phase.Both: ExitBothPart(); break;            case Phase.End: ExitEndPart(); break;        }    }    private void ExitStartPart()    {        Debug.Log("Exit Start");    }    private void ExitRightPart()    {        Debug.Log("Exit Right");    }        private void ExitLeftPart()    {        Debug.Log("Enter Left");    }    private void ExitBothPart()    {        Debug.Log("Enter Both");            }    private void ExitEndPart()    {        Debug.Log("Exit End");        StartCoroutine(SceneLoad());    }    private IEnumerator SceneLoad()    {        yield return new WaitForSecondsRealtime(1f);        Addressables.LoadSceneAsync("Scene/Papermaking", LoadSceneMode.Single);    }       public void OnPressStartGameButton()    {        ChangePhase(Phase.Right);    }            public Phase CurrentPhase()    {        return currentPhase;    }}   }